import{c as e,Q as a,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"Claude Code 核心开发者 Thariq 的「开发日志」提示词","description":"","frontmatter":{"title":"Claude Code 核心开发者 Thariq 的「开发日志」提示词","author":"Meng Shao (@shao__meng) — AI 团队顾问 & 企业 AI 培训，30.6k followers","date":"2026-05-19T00:00:00.000Z","source":"https://x.com/shao__meng/status/2056535561540948056","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-19-@shao__meng-948056.md","filePath":"research/tweets/2026-05-19-@shao__meng-948056.md","lastUpdated":1779894392000}'),i={name:"research/tweets/2026-05-19-@shao__meng-948056.md"};function n(s,t,l,d,h,p){return a(),o("div",null,[...t[0]||(t[0]=[r(`<h1 id="claude-code-核心开发者-thariq-的「开发日志」提示词" tabindex="-1">Claude Code 核心开发者 Thariq 的「开发日志」提示词 <a class="header-anchor" href="#claude-code-核心开发者-thariq-的「开发日志」提示词" aria-label="Permalink to &quot;Claude Code 核心开发者 Thariq 的「开发日志」提示词&quot;">​</a></h1><p><strong>注意</strong>：note tweet 格式，fxtwitter API 僅能取得 intro，全文請至原始連結閱讀</p><ul><li><strong>URL</strong>：<a href="https://x.com/shao__meng/status/2056535561540948056" target="_blank" rel="noreferrer">https://x.com/shao__meng/status/2056535561540948056</a></li><li><strong>作者</strong>：Meng Shao (@shao__meng) — AI 团队顾问 &amp; 企业 AI 培训，30.6k followers</li><li><strong>日期</strong>：2026-05-19</li><li><strong>互動</strong>：109 likes · 11 RT · 124 bookmarks · 10,857 views</li><li><strong>引用推文</strong>：<a href="https://x.com/trq212/status/2056415973125796184%EF%BC%88@trq212" target="_blank" rel="noreferrer">https://x.com/trq212/status/2056415973125796184（@trq212</a> 原始 prompt，9k likes · 11.5k bookmarks · 728k views）</li></ul><hr><h2 id="全文-note-tweet-intro" tabindex="-1">全文（Note Tweet Intro） <a class="header-anchor" href="#全文-note-tweet-intro" aria-label="Permalink to &quot;全文（Note Tweet Intro）&quot;">​</a></h2><p>Claude Code 核心开发者 Thariq 带来自己高频使用的「开发日志」提示词</p><p>@trq212 这段提示词解决了 AI 协作编码中最棘手的结构性问题：规格永远写不完整，但人又无法实时跟踪 AI 的每一个判断。</p><p>传统的两种极端都失败：</p><ol><li>过度规约：试图在 spec 里穷举所有边界情况——不现实，且拖慢启动</li><li>完全放手：让 agent 自由发挥——结果是大量隐性决策埋藏在 diff 里，code review 时才发现，返工成本极高</li></ol><p>这个提示词走的是第三条路：承认歧义不可避免，把&quot;判断&quot;这个动作本身变成可审计的产物。</p><p>为什么有效：</p><ul><li>降低模型的&quot;过度澄清&quot;倾向：模型不必反复打断你问问题，可以自主推进</li><li>把隐性决策外化：原本藏在代码里的&quot;为什么这样写&quot;被显式写出来，review 时直接对照笔记，而不是逆向工程 diff</li><li>结构化的四个维度覆盖实施中所有&quot;非代码信息&quot;： <ul><li>Design decisions = 填补 spec 的空白</li><li>Deviations = 偏离 spec 的地方（最危险，必须显式）</li><li>Tradeoffs = 没走的路（防止 reviewer 重复思考同样的备选）</li><li>Open questions = 需要人类回环的点</li></ul></li><li>HTML/Markdown 作为载体：轻量、可读、可与代码同 PR 提交，不需要额外工具</li></ul><p>值得借鉴的 prompt 设计原则：</p><ul><li>给模型一个&quot;合法的出口&quot;，而不是逼它在歧义前停下或瞎猜</li><li>要求结构化产物（四个明确分类），比开放式&quot;写点笔记&quot;质量高一个数量级</li><li>用单独文件而非 inline 注释——保持代码干净，同时让元信息集中、可搜索</li><li>二次迭代本身是个示范：第一版凭直觉写，第二版让 Claude 帮忙结构化</li></ul><hr><h2 id="核心提示詞原文-trq212" tabindex="-1">核心提示詞原文（@trq212） <a class="header-anchor" href="#核心提示詞原文-trq212" aria-label="Permalink to &quot;核心提示詞原文（@trq212）&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Implement &lt;SPEC&gt;. As you work, maintain a running implementation-notes.html file that captures anything I should know about how the implementation diverges from or interprets the spec, including:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>· Design decisions: choices you made where the spec was ambiguous</span></span>
<span class="line"><span>· Deviations: places where you intentionally departed from the spec, and why</span></span>
<span class="line"><span>· Tradeoffs: alternatives you considered and why you picked what you did</span></span>
<span class="line"><span>· Open questions: anything you&#39;d want me to confirm or revise</span></span></code></pre></div><hr><h2 id="分析" tabindex="-1">分析 <a class="header-anchor" href="#分析" aria-label="Permalink to &quot;分析&quot;">​</a></h2><h3 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h3><p>Claude Code 核心開發者 Thariq 的高頻 prompt：讓 agent 維護 implementation-notes.html，將所有隱性判斷外化為可審計產物。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><strong>第三條路</strong>：spec 不可能完整 + agent 不能完全放手 → 讓「判斷行為本身」成為可審計產物</li><li><strong>四維結構</strong>：Design decisions（填補 spec 空白）· Deviations（最危險，必須顯式）· Tradeoffs（防止 reviewer 重覆思考）· Open questions（需人類介入點）</li><li><strong>降低過度澄清</strong>：給 model 合法出口，讓其自主推進，不用反覆打斷問問題</li><li><strong>隱性決策外化</strong>：review 時對照 notes 而非逆向工程 diff，大幅降低 code review 成本</li></ol><h3 id="關鍵數據" tabindex="-1">關鍵數據 <a class="header-anchor" href="#關鍵數據" aria-label="Permalink to &quot;關鍵數據&quot;">​</a></h3><ul><li>原始 @trq212 推文：9,010 likes · 11,522 bookmarks · 728,379 views（爆款）</li><li>@trq212 = Claude Code @ Anthropic 核心開發者（primary source，極高信度）</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li><strong>受限於截斷</strong>：note tweet，但核心 prompt 原文已在推文中完整呈現，價值完整</li><li><strong>直接可落地</strong>：prompt 本身就是交付物，可立即在任何 implementation 任務中使用</li><li><strong>與本 workspace 完美契合</strong>：R1 Think Before Coding（先顯露假設）+ 本 prompt 的 implementation-notes 互補——前者用於實作前，後者用於實作中</li></ol><hr><h2 id="_5-維度評分" tabindex="-1">5 維度評分 <a class="header-anchor" href="#_5-維度評分" aria-label="Permalink to &quot;5 維度評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>10/10</td><td>提示詞本身就是工具，直接複製使用；與 R1 規則互補，填補「實作中」的透明度缺口</td></tr><tr><td>B. 創新性</td><td>8/10</td><td>來自 Claude Code 開發者第一手實戰；四維結構化明確超越「隨便寫些筆記」</td></tr><tr><td>C. 證據品質</td><td>7/10</td><td>高可信來源（開發者本人）；原推文爆款（11.5k bookmarks）；note tweet 截斷</td></tr><tr><td>D. 技術深度</td><td>8/10</td><td>Prompt 設計原則分析紮實；四個維度對應具體場景解釋清楚</td></tr><tr><td>E. 泛化性</td><td>9/10</td><td>適用任何語言、任何 codebase 的 AI 協作編碼場景</td></tr></tbody></table><p><strong>加權總分</strong>：10×0.3 + 8×0.2 + 7×0.2 + 8×0.15 + 9×0.15 = <strong>8.55/10</strong></p><hr><h2 id="整合決策" tabindex="-1">整合決策 <a class="header-anchor" href="#整合決策" aria-label="Permalink to &quot;整合決策&quot;">​</a></h2><p><strong>SKILL</strong> — 靜態提示詞/方法論，可立即作為 skill 供實作任務使用</p><p><strong>建議行動（高優先）</strong>：</p><ul><li>可直接加入 CLAUDE.md 或建立 <code>/implementation-notes</code> skill</li><li>標準用法：每次開始 implementation 任務時附加此 prompt</li><li>與 R1（Think Before Coding）組合：R1 → 實作前顯露假設；本 prompt → 實作中記錄判斷</li></ul>`,36)])])}const m=e(i,[["render",n]]);export{c as __pageData,m as default};
